1	const containsCell = (grid: [number, number][], [x, y]: [number, number]): boolean =>
2	  grid.some(([cx, cy]) => cx === x && cy === y);
3	
4	const countNeighbors = (cell: [number, number], cells: [number, number][]): number => {
5	  const [x, y] = cell;
6	  let neighborCount = 0;
7	  for (const [cx, cy] of cells) {
8	    if (cx === x && cy === y) continue;
9	    if (Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1) neighborCount++;
10	  }
11	  return neighborCount;
12	};
13	
14	export function nextGeneration(cells: [number, number][]): [number, number][] {
15	  const survivors = cells.filter(cell => {
16	    const neighborCount = countNeighbors(cell, cells);
17	    return neighborCount === 2 || neighborCount === 3;
18	  });
19	
20	  const adjacentDeadCells: [number, number][] = [];
21	  for (const [x, y] of cells) {
22	    for (let dx = -1; dx <= 1; dx++) {
23	      for (let dy = -1; dy <= 1; dy++) {
24	        if (dx === 0 && dy === 0) continue;
25	        const nx = x + dx;
26	        const ny = y + dy;
27	        const isLive = containsCell(cells, [nx, ny]);
28	        const alreadyAdded = containsCell(adjacentDeadCells, [nx, ny]);
29	        if (!isLive && !alreadyAdded) {
30	          adjacentDeadCells.push([nx, ny]);
31	        }
32	      }
33	    }
34	  }
35	
36	  const born = adjacentDeadCells.filter(cell => countNeighbors(cell, cells) === 3);
37	
38	  return [...survivors, ...born];
39	}
